package escalation

import (
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// InferTier returns a recommended ModelTier for a bead based on its metadata.
// It inspects, in priority order: an explicit "tier:" label, the kind/priority
// labels and IssueType, then falls back to an estimated-scope heuristic on the
// description length.
//
// The default for a bead with no useful signal is TierCheap, matching the
// hot-fix behavior in cmd/agent_cmd.go runAgentExecuteLoopImpl that this
// engine replaces. Aligns with the endpoint-first routing redesign goal of
// cheap-by-default with metadata-driven escalation.
func InferTier(b *bead.Bead) ModelTier {
	if b == nil {
		return TierCheap
	}

	kindLabel := ""
	priorityLabel := ""
	for _, raw := range b.Labels {
		l := strings.ToLower(strings.TrimSpace(raw))
		if l == "" {
			continue
		}
		// Explicit override wins.
		if v, ok := strings.CutPrefix(l, "tier:"); ok {
			switch strings.TrimSpace(v) {
			case "smart":
				return TierSmart
			case "standard":
				return TierStandard
			case "cheap":
				return TierCheap
			}
		}
		if v, ok := strings.CutPrefix(l, "kind:"); ok {
			kindLabel = strings.TrimSpace(v)
		}
		if v, ok := strings.CutPrefix(l, "priority:"); ok {
			priorityLabel = strings.TrimSpace(v)
		}
	}

	// Priority drives the floor: critical/high work gets smart, low/trivial
	// is happy at cheap. Medium falls through to kind- and scope-based logic.
	switch priorityLabel {
	case "critical", "urgent":
		return TierSmart
	case "high":
		// High priority bugs/incidents go to smart; high enhancements stay
		// at standard so we don't burn smart-tier budget on routine work.
		if isBugKind(kindLabel) || isBugKind(b.IssueType) {
			return TierSmart
		}
		return TierStandard
	case "low", "trivial":
		return TierCheap
	}

	kind := kindLabel
	if kind == "" {
		kind = strings.ToLower(strings.TrimSpace(b.IssueType))
	}
	switch {
	case isBugKind(kind):
		return TierStandard
	case isCheapKind(kind):
		return TierCheap
	case isStandardKind(kind):
		return TierStandard
	}

	// Estimated scope from description length. Long, dense descriptions tend
	// to indicate larger work; short descriptions are typically mechanical.
	descLen := len(b.Description) + len(b.Acceptance)
	switch {
	case descLen >= 4000:
		return TierSmart
	case descLen >= 1500:
		return TierStandard
	default:
		return TierCheap
	}
}

func isBugKind(s string) bool {
	switch strings.ToLower(strings.TrimSpace(s)) {
	case "bug", "fix", "incident", "regression", "defect":
		return true
	}
	return false
}

func isCheapKind(s string) bool {
	switch strings.ToLower(strings.TrimSpace(s)) {
	case "chore", "docs", "doc", "documentation", "cleanup", "typo", "rename":
		return true
	}
	return false
}

func isStandardKind(s string) bool {
	switch strings.ToLower(strings.TrimSpace(s)) {
	case "enhancement", "feature", "story", "task", "refactor", "test":
		return true
	}
	return false
}

// TierToProfile maps a ModelTier to the routing profile string consumed by
// agent.NormalizeRoutingProfile / LoadAndResolve. Tier names align with
// profile names in the built-in catalog (smart/standard/cheap).
func TierToProfile(t ModelTier) string {
	switch t {
	case TierSmart:
		return "smart"
	case TierStandard:
		return "standard"
	case TierCheap:
		return "cheap"
	}
	return "cheap"
}

package escalation

import (
	"strings"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

func TestInferTier_NilBead(t *testing.T) {
	if got := InferTier(nil); got != TierCheap {
		t.Fatalf("nil bead: want %q, got %q", TierCheap, got)
	}
}

func TestInferTier_ExplicitTierLabel(t *testing.T) {
	cases := []struct {
		label string
		want  ModelTier
	}{
		{"tier:smart", TierSmart},
		{"tier:standard", TierStandard},
		{"tier:cheap", TierCheap},
		{"TIER:SMART", TierSmart},
	}
	for _, c := range cases {
		b := &bead.Bead{Labels: []string{c.label}}
		if got := InferTier(b); got != c.want {
			t.Errorf("label %q: want %q, got %q", c.label, c.want, got)
		}
	}
}

func TestInferTier_ExplicitTierLabelOverridesPriority(t *testing.T) {
	// An explicit tier wins over priority:critical, which would otherwise
	// route to smart.
	b := &bead.Bead{Labels: []string{"priority:critical", "tier:cheap"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("explicit tier should win: got %q", got)
	}
}

func TestInferTier_PriorityCritical(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:critical", "kind:chore"}}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("critical priority: want smart, got %q", got)
	}
}

func TestInferTier_PriorityHighBug(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:high", "kind:bug"}}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("high-priority bug: want smart, got %q", got)
	}
}

func TestInferTier_PriorityHighEnhancement(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:high", "kind:enhancement"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("high-priority enhancement: want standard, got %q", got)
	}
}

func TestInferTier_PriorityLow(t *testing.T) {
	b := &bead.Bead{Labels: []string{"priority:low", "kind:bug"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("low priority: want cheap, got %q", got)
	}
}

func TestInferTier_KindBug(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:bug"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("bug kind: want standard, got %q", got)
	}
}

func TestInferTier_KindChore(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:chore"}}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("chore kind: want cheap, got %q", got)
	}
}

func TestInferTier_KindEnhancement(t *testing.T) {
	b := &bead.Bead{Labels: []string{"kind:enhancement"}}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("enhancement kind: want standard, got %q", got)
	}
}

func TestInferTier_IssueTypeFallback(t *testing.T) {
	b := &bead.Bead{IssueType: "bug"}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("issue_type bug: want standard, got %q", got)
	}
}

func TestInferTier_ScopeShort(t *testing.T) {
	b := &bead.Bead{Description: "fix typo"}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("short scope: want cheap, got %q", got)
	}
}

func TestInferTier_ScopeMedium(t *testing.T) {
	b := &bead.Bead{Description: strings.Repeat("x", 2000)}
	if got := InferTier(b); got != TierStandard {
		t.Fatalf("medium scope: want standard, got %q", got)
	}
}

func TestInferTier_ScopeLarge(t *testing.T) {
	b := &bead.Bead{Description: strings.Repeat("x", 5000)}
	if got := InferTier(b); got != TierSmart {
		t.Fatalf("large scope: want smart, got %q", got)
	}
}

func TestInferTier_NoMetadataDefaultsCheap(t *testing.T) {
	b := &bead.Bead{Title: "do thing"}
	if got := InferTier(b); got != TierCheap {
		t.Fatalf("no metadata: want cheap, got %q", got)
	}
}

func TestTierToProfile(t *testing.T) {
	cases := map[ModelTier]string{
		TierSmart:    "smart",
		TierStandard: "standard",
		TierCheap:    "cheap",
		ModelTier(""): "cheap",
	}
	for tier, want := range cases {
		if got := TierToProfile(tier); got != want {
			t.Errorf("TierToProfile(%q): want %q, got %q", tier, want, got)
		}
	}
}

